import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;

import java.lang.reflect.Field;
import java.util.Arrays;

class CSVFormatEqualsTest {

    private CSVFormat createCSVFormat(char delimiter, QuoteMode quoteMode, Character quoteCharacter,
                                      Character commentMarker, Character escapeCharacter, String nullString,
                                      String[] header, boolean ignoreSurroundingSpaces, boolean ignoreEmptyLines,
                                      boolean skipHeaderRecord, String recordSeparator) throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Using reflection to set private final fields
        setField(format, "delimiter", delimiter);
        setField(format, "quoteMode", quoteMode);
        setField(format, "quoteCharacter", quoteCharacter);
        setField(format, "commentMarker", commentMarker);
        setField(format, "escapeCharacter", escapeCharacter);
        setField(format, "nullString", nullString);
        setField(format, "header", header);
        setField(format, "ignoreSurroundingSpaces", ignoreSurroundingSpaces);
        setField(format, "ignoreEmptyLines", ignoreEmptyLines);
        setField(format, "skipHeaderRecord", skipHeaderRecord);
        setField(format, "recordSeparator", recordSeparator);

        return format;
    }

    private void setField(Object target, String fieldName, Object value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField(fieldName);
        field.setAccessible(true);

        // Remove final modifier for the field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        field.set(target, value);
    }

    @Test
    void testEquals_SameInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.equals(format));
    }

    @Test
    void testEquals_Null() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.equals(null));
    }

    @Test
    void testEquals_DifferentClass() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.equals("some string"));
    }

    @Test
    void testEquals_DifferentDelimiter() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(';', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_DifferentQuoteMode() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_QuoteCharacterNullDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, null, '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_QuoteCharacterEqual() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_CommentMarkerNullDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', null, '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_CommentMarkerEqual() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_EscapeCharacterNullDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', null, null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_EscapeCharacterEqual() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_NullStringNullDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\", "NULL",
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_NullStringEqual() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', "NULL",
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', "NULL",
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_HeaderDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "c"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_HeaderEqual() throws Exception {
        String[] header = new String[]{"a", "b"};
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                header, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_IgnoreSurroundingSpacesDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, true, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_IgnoreEmptyLinesDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, false, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_SkipHeaderRecordDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, true, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_RecordSeparatorNullDiffer() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, null);
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_RecordSeparatorEqual() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }
}
